class Solution {
    public int distinctSequences(int n) {
        long mod = 1000000007;
        long[][] dp = new long[n + 1][6];
        for (int i = 1; i <= 5; i++) {
            dp[1][i] = 1;
        }
        for (int i = 2; i <= n; i++) {
            for (int j = 1; j <= 5; j++) {
                for (int k = 1; k <= 5; k++) {
                    if (gcd(j, k) == 1) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % mod;
                    }
                }
            }
        }
        long ans = 0;
        for (int i = 1; i <= 5; i++) {
            ans = (ans + dp[n][i]) % mod;
        }
        return (int) ans;
    }
    private int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
